1	/**
2	 * Pure config resolver — no I/O, no side effects.
3	 *
4	 * Accepts a RawConfig (straight from the YAML parser) and the absolute path
5	 * of the directory containing .yoke.yml, returns a ResolvedConfig with all
6	 * relative path fields converted to absolute paths.
7	 *
8	 * Resolved fields (relative → absolute, base = configDir):
9	 *   phases[*].prompt_template
10	 *   phases[*].cwd                          (if present)
11	 *   phases[*].output_artifacts[*].schema   (if present)
12	 *   worktrees.teardown.script              (if present)
13	 *
14	 * NOT resolved — runtime-relative to the worktree, unknown at load time:
15	 *   pipeline.stages[*].items_from
16	 *   phases[*].output_artifacts[*].path
17	 */
18	
19	import path from 'node:path';
20	import type { RawConfig, ResolvedConfig } from '../../shared/types/config.js';
21	
22	/**
23	 * Resolve all config-relative paths in `raw` to absolute paths.
24	 *
25	 * The original `raw` object is NOT mutated; a deep clone is made first.
26	 * `configDir` must be an absolute path (the directory containing .yoke.yml).
27	 */
28	export function resolveConfig(raw: Readonly<RawConfig>, configDir: string): ResolvedConfig {
29	  const clone = structuredClone(raw) as RawConfig;
30	
31	  // Phase-level paths
32	  for (const phase of Object.values(clone.phases)) {
33	    phase.prompt_template = toAbsolute(phase.prompt_template, configDir);
34	
35	    if (phase.cwd !== undefined) {
36	      phase.cwd = toAbsolute(phase.cwd, configDir);
37	    }
38	
39	    if (phase.output_artifacts !== undefined) {
40	      for (const artifact of phase.output_artifacts) {
41	        if (artifact.schema !== undefined) {
42	          artifact.schema = toAbsolute(artifact.schema, configDir);
43	        }
44	      }
45	    }
46	  }
47	
48	  // Worktree teardown hook script (hook path)
49	  if (clone.worktrees?.teardown?.script !== undefined) {
50	    clone.worktrees.teardown.script = toAbsolute(clone.worktrees.teardown.script, configDir);
51	  }
52	
53	  return { ...clone, configDir };
54	}
55	
56	/** Resolve `p` against `base` if relative; return absolute paths unchanged. */
57	function toAbsolute(p: string, base: string): string {
58	  return path.isAbsolute(p) ? p : path.resolve(base, p);
59	}
