1	/**
2	 * Yoke Fastify HTTP + WebSocket server.
3	 *
4	 * This module replaces the interim Node.js http.Server in http.ts.  It
5	 * implements:
6	 *   - All HTTP companion endpoints from protocol-websocket.md §7.
7	 *   - WebSocket route at /stream (protocol per ws.ts).
8	 *   - Exclusive 127.0.0.1 binding (D57, RC: no 0.0.0.0 code path).
9	 *
10	 * Design invariants:
11	 *   - All reads use db.reader() (read-only connection).
12	 *   - No SQLite writes in this module (RC-3). The attention ack endpoint
13	 *     delegates the write to an injected AckAttentionFn callback so the API
14	 *     layer itself has no write path.
15	 *   - No authentication middleware (D57).
16	 *   - No 0.0.0.0 bind path exists anywhere in this file.
17	 */
18	
19	import Fastify, { type FastifyInstance, type FastifyRequest, type FastifyReply } from 'fastify';
20	import fastifyWebsocket, { type SocketStream } from '@fastify/websocket';
21	import type { DbPool } from '../storage/db.js';
22	import { readLogPage } from '../session-log/reader.js';
23	import {
24	  SessionSeqStore,
25	  BackfillBuffer,
26	  createWsHandler,
27	} from './ws.js';
28	import { IdempotencyStore } from './idempotency.js';
29	
30	// ---------------------------------------------------------------------------
31	// Internal helpers
32	// ---------------------------------------------------------------------------
33	
34	function badRequest(reply: FastifyReply, message: string): FastifyReply {
35	  return reply.status(400).send({ error: message });
36	}
37	
38	function notFound(reply: FastifyReply, message = 'not found'): FastifyReply {
39	  return reply.status(404).send({ error: message });
40	}
41	
42	// ---------------------------------------------------------------------------
43	// Snapshot helpers
44	// ---------------------------------------------------------------------------
45	
46	interface WorkflowRow {
47	  id: string;
48	  name: string;
49	  status: string;
50	  current_stage: string | null;
51	  created_at: string;
52	  updated_at: string;
53	}
54	
55	// ---------------------------------------------------------------------------
56	// Server factory
57	// ---------------------------------------------------------------------------
58	
59	export interface ServerOptions {
60	  /**
61	   * Bind host — MUST be '127.0.0.1'. Passing any other value throws at
62	   * listen time. Default: '127.0.0.1'.
63	   */
64	  host?: '127.0.0.1';
65	  /** Server port. 0 = OS-assigned (default for tests). */
66	  port?: number;
67	}
68	
69	/** Shared in-memory state for the WS layer — exposed so tests and the pipeline engine integration can push frames. */
70	export interface ServerState {
71	  seqStore: SessionSeqStore;
72	  backfillBuffer: BackfillBuffer;
73	  idempotency: IdempotencyStore;
74	}
75	
76	export interface ServerHandle {
77	  fastify: FastifyInstance;
78	  state: ServerState;
79	}
80	
81	/**
82	 * Result returned by AckAttentionFn to the API layer.
83	 * The callback owns both the read and the write for the ack operation so that
84	 * the API layer has no SQLite write path (RC-3).
85	 */
86	export type AckAttentionResult =
87	  | { status: 'acknowledged'; id: number }
88	  | { status: 'already_acknowledged'; id: number }
89	  | { status: 'not_found' };
90	
91	/**
92	 * Callback that handles POST /api/workflows/:id/attention/:attentionId/ack.
93	 * Implementations must: verify the attention item exists and belongs to
94	 * workflowId, check acknowledged_at, write acknowledged_at = datetime('now')
95	 * if not already set, and return the appropriate result.
96	 *
97	 * The write MUST NOT happen inside the API layer (RC-3). Callers inject this
98	 * callback so the actual SQLite write lives in the pipeline engine layer.
99	 */
100	export type AckAttentionFn = (workflowId: string, attentionId: number) => AckAttentionResult;
101	
102	/**
103	 * Optional callbacks injected into the server at creation time.
104	 * These allow the API layer to delegate writes to the pipeline engine layer
105	 * without the API module having any SQLite write path (RC-3).
106	 */
107	export interface ServerCallbacks {
108	  /**
109	   * Called when a client POSTs to
110	   * /api/workflows/:id/attention/:attentionId/ack.
111	   * If omitted, the endpoint returns 501 Not Implemented.
112	   */
113	  ackAttention?: AckAttentionFn;
114	}
115	
116	/**
117	 * Creates and configures the Fastify server.
118	 *
119	 * Callers must await fastify.listen(...) to start accepting connections.
120	 * The returned instance's .server.address() gives the bound port.
121	 *
122	 * @param db         DbPool opened by the caller.
123	 * @param callbacks  Optional injected handlers for write operations (RC-3).
124	 */
125	export async function createServer(db: DbPool, callbacks: ServerCallbacks = {}): Promise<ServerHandle> {
126	  const fastify = Fastify({ logger: false });
127	
128	  // Shared state for the WS layer.
129	  const seqStore = new SessionSeqStore();
130	  const backfillBuffer = new BackfillBuffer();
131	  const idempotency = new IdempotencyStore();
132	
133	  // Register WebSocket plugin.
134	  await fastify.register(fastifyWebsocket);
135	
136	  // WebSocket route at /stream (§4 Lifecycle).
137	  // Registered directly on the root fastify instance so it inherits the
138	  // @fastify/websocket plugin decoration without sub-plugin scoping issues.
139	  const wsHandler = createWsHandler({ db, idempotency, seqStore, backfillBuffer });
140	  fastify.get('/stream', { websocket: true }, (connection: SocketStream) => {
141	    wsHandler(connection.socket);
142	  });
143	
144	  // -------------------------------------------------------------------------
145	  // §7 HTTP companion endpoints
146	  // All read from db.reader() — no workflow/item state writes.
147	  // -------------------------------------------------------------------------
148	
149	  // GET /api/workflows?status=&q=&before=&limit=
150	  // Keyset pagination (D47). Ordered by created_at DESC.
151	  fastify.get(
152	    '/api/workflows',
153	    async (req: FastifyRequest, reply: FastifyReply) => {
154	      const qs = req.query as Record<string, string | undefined>;
155	      const limitRaw = parseInt(qs.limit ?? '20', 10);
156	      if (!isFinite(limitRaw) || limitRaw < 1) return badRequest(reply, 'limit must be a positive integer');
157	      const limit = Math.min(limitRaw, 100);
158	
159	      let sql = 'SELECT id, name, status, current_stage, created_at, updated_at FROM workflows WHERE 1=1';
160	      const params: unknown[] = [];
161	
162	      if (qs.status) {
163	        sql += ' AND status = ?';
164	        params.push(qs.status);
165	      }
166	      if (qs.q) {
167	        sql += ' AND name LIKE ?';
168	        params.push(`%${qs.q}%`);
169	      }
170	      if (qs.before) {
171	        sql += ' AND created_at < ?';
172	        params.push(qs.before);
173	      }
174	      sql += ` ORDER BY created_at DESC LIMIT ${limit + 1}`;
175	
176	      const rows = db.reader().prepare(sql).all(...params) as WorkflowRow[];
177	      const hasMore = rows.length > limit;
178	      const workflows = hasMore ? rows.slice(0, limit) : rows;
179	
180	      return reply.send({
181	        workflows,
182	        hasMore,
183	        nextBefore: hasMore ? workflows[workflows.length - 1].created_at : null,
184	      });
185	    },
186	  );
187	
188	  // GET /api/workflows/:id/timeline
189	  // Merged SQLite events + JSONL (§Obs, D34).
190	  fastify.get(
191	    '/api/workflows/:id/timeline',
192	    async (req: FastifyRequest<{ Params: { id: string } }>, reply: FastifyReply) => {
193	      const { id } = req.params;
194	      const reader = db.reader();
