252	// ---------------------------------------------------------------------------
253	// JigProcessManager (exported)
254	// ---------------------------------------------------------------------------
255	
256	/**
257	 * Production ProcessManager. Spawns whatever command + args the caller
258	 * provides — reads exclusively from SpawnOpts. No string constants here.
259	 */
260	export class JigProcessManager implements ProcessManager {
261	  async spawn(opts: SpawnOpts): Promise<SpawnHandle> {
262	    const { command, args, cwd, env, promptBuffer, gracePeriodMs = 10_000, logWriter = null } = opts;
263	
264	    const child = nodeSpawn(command, args, {
265	      cwd,
266	      stdio: ['pipe', 'pipe', 'pipe'],
267	      // Merge caller env over process.env. Never pass undefined as the env
268	      // option — that is equivalent to inheriting the full environment, which
269	      // is the intended behaviour here.
270	      env: env !== undefined ? { ...process.env, ...env } : { ...process.env },
271	      // detached:true creates a new session + process group for the child
272	      // (pgid === child.pid on POSIX). This ensures kill(-pgid, signal)
273	      // delivers the signal to the entire subtree, not just the immediate child.
274	      detached: true,
275	    });
276	
277	    // Construct the handle first — its _wireStdin() call registers the stdin
278	    // 'error' handler synchronously. EPIPE is asynchronous, so by the time
279	    // it fires the handler is already in place.
280	    const handle = new JigSpawnHandle(child, gracePeriodMs, logWriter);
281	
282	    // Zombie reap: unref() allows the Node.js event loop to exit without
283	    // waiting for this child. The OS adopts and reaps the process if Yoke
284	    // exits first. We still receive 'exit', 'stdout_line', 'stderr_data', and
285	    // 'error' events — unref() only affects the event-loop exit condition.
286	    child.unref();
287	
288	    // One-shot stdin delivery: write the entire prompt buffer then close the
289	    // pipe. The 'error' handler registered above catches EPIPE if the child
290	    // closes stdin before we finish writing.
291	    child.stdin!.end(promptBuffer);
292	
293	    return handle;
294	  }
295	}
