// Paged stream-json fetch (D48a). Reads from JSONL file via readLogPage.
fastify.get(
  '/api/sessions/:id/log',
  async (req: FastifyRequest<{ Params: { id: string } }>, reply: FastifyReply) => {
    const { id } = req.params;
    const qs = req.query as Record<string, string | undefined>;

