    if (!isFinite(sinceSeqRaw) || sinceSeqRaw < 0) return badRequest(reply, 'sinceSeq must be a non-negative integer');
    if (!isFinite(limitRaw) || limitRaw < 1) return badRequest(reply, 'limit must be a positive integer');

