/**
 * yoke doctor — pre-flight checks for the Yoke environment.
 *
 * Checks:
 *   1. Node.js >= 20
 *   2. SQLite accessible (open an in-memory DB with better-sqlite3)
 *   3. git >= 2.20
 *   4. .yoke.yml present and valid (loadConfig)
 *
 * For each check prints a PASS / FAIL row with actionable remediation text
 * on failure (RC: "not just 'failed'").
 *
 * Exit code: 0 if all checks pass, 1 if any check fails.
 */

import { execFileSync } from 'node:child_process';
import path from 'node:path';
import type { Command } from 'commander';
import { loadConfig } from '../server/config/loader.js';
import { ConfigLoadError } from '../server/config/errors.js';

// ---------------------------------------------------------------------------
// Check result type
// ---------------------------------------------------------------------------

export interface DoctorCheck {
  name: string;
  passed: boolean;
  /** Short summary. */
  message: string;
  /** Remediation text shown only on failure. */
  remediation?: string;
}

// ---------------------------------------------------------------------------
// Individual checks
// ---------------------------------------------------------------------------

/** 1. Node.js version >= 20 */
export function checkNode(): DoctorCheck {
  const raw = process.versions.node; // e.g. "20.11.0"
  const major = parseInt(raw.split('.')[0], 10);
  if (major >= 20) {
    return { name: 'Node.js >= 20', passed: true, message: `Node.js ${raw}` };
  }
  return {
    name: 'Node.js >= 20',
    passed: false,
    message: `Node.js ${raw} (too old)`,
    remediation:
      `Yoke requires Node.js 20 or later.\n` +
      `Install via https://nodejs.org/ or use nvm: nvm install 20`,
  };
}

/** 2. SQLite accessible via better-sqlite3 */
export function checkSqlite(): DoctorCheck {
  try {
    // Dynamic import is too slow in a CLI; use synchronous require-style check.
    // We call better-sqlite3 through the same code path used at runtime.
    const { openDbPool } = await_import_sync_sqlite();
    const pool = openDbPool(':memory:');
    pool.writer.exec('SELECT 1');
    pool.close();
    return { name: 'SQLite accessible', passed: true, message: 'better-sqlite3 opened :memory: DB' };
  } catch (err) {
    return {
      name: 'SQLite accessible',
      passed: false,
      message: `better-sqlite3 failed: ${(err as Error).message}`,
      remediation:
        `better-sqlite3 requires a native build.\n` +
        `Run: npm rebuild better-sqlite3\n` +
        `If that fails, check that your Node.js version matches the installed native module\n` +
        `(node --version vs the version used during npm install).`,
    };
  }
}

/**
 * Synchronous wrapper around the SQLite import.
 * better-sqlite3 is a CommonJS native module; it loads synchronously even
 * in an ESM context via createRequire.
 */
function await_import_sync_sqlite(): { openDbPool: typeof import('../server/storage/db.js').openDbPool } {
  // ESM dynamic import is async, but we need synchronous execution here.
  // We use a trick: call the already-loaded module via a relative path
  // import that was resolved at module load time. Since better-sqlite3
  // is used everywhere in the server, the module is already in the module
  // registry by the time doctor runs.
  //
  // For the CLI use case, we just use the import() promise in a sync-ish way
  // by relying on the fact that the module cache is warm.
  // In practice, the check runs inside an async action handler, so we can
