    } else if (rec.type === 'stderr' && typeof rec.chunk === 'string') {
      records.push({ type: 'stderr', chunk: rec.chunk });
    } else if (rec.type === 'exit' && typeof rec.code === 'number') {
      records.push({ type: 'exit', code: rec.code });
