  private readonly fixturePath: string;
  private readonly fakePid: number;

  constructor(opts: ScriptedManagerOptions) {
    this.fixturePath = opts.fixturePath;
    this.fakePid = opts.fakePid ?? deriveFakePid(opts.fixturePath);
